mapper.select:
select cs.*,
       c.course_name,
       u.real_name as student_name,
       concat(s.week_day, ' ', s.start_section, '-', s.end_section, '节') as schedule_info
from course_selection cs
         left join course_info c on cs.course_id = c.id
         left join sys_user u on cs.student_id = u.id
         left join course_schedule s on cs.schedule_id = s.id


        and cs.schedule_id = #{scheduleId}


        and cs.student_id = #{studentId}


        and cs.select_status = #{selectStatus}


        and s.teacher_id = #{teacherId}


order by cs.id desc
